var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"크하하하, 아프긴커녕 맛있기만 하군.","JPN":"クハハハ、痛いどころか、こりゃ美味いな。","ENG":"Haha, it's not painful at all. It's only tasty.","TWN":"哈哈哈，不僅不痛，反而還很美味。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_04"},{"id":"L4_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"네가 가진 무기는 그게 전부냐?","JPN":"お前が持っている武器はそれで終わりか？","ENG":"Is that really all the weapons you have?","TWN":"你的武器，就只有這點嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_07"},{"id":"L5_1","type":"dialog","speaker":"HELPER_NPC_TV_NULL","text":{"KOREA":"이럴 수가…! 슬라임 백작이 우리가 가진 무기를 전부 먹어 치웠어.","JPN":"どうしよう……！　スライム伯爵が私たちが持っている武器を全部食いつくしちゃったよ。","ENG":"This can't be...! Count Slime has eaten all the weapons we had.","TWN":"怎麼會這樣……！史萊姆伯爵竟把我們所有的武器都吃掉了。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HELPER_NPC_TV_NULL","text":{"KOREA":"게다가 그 무기를 자신이 이용할 수 있다니, 이대로는 위험해!","JPN":"しかもその武器を自分の物として使えるなんて、このままじゃ危ないよ！","ENG":"And now, he can use those weapons against us. This is dangerous!","TWN":"而且它還能利用這些武器，這下可危險了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"진정해, 미샤. 아직 끝난 게 아니야.","JPN":"落ち着くんだ、ミシャ。まだ終わった訳ではない。","ENG":"Calm down, Misha. It's not over yet.","TWN":"冷靜點，米莎。一切還沒結束！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAMEN_NPC_TV_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"DOC_NPC_TV_NULL","text":{"KOREA":"물론이지. 우리에겐 비밀병기가 남아 있으니까.","JPN":"もちろんだ。俺たちにはまだ秘密兵器が残っている。","ENG":"Of course. We still have our secret weapon left.","TWN":"當然，我們可還有秘密武器呢！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAMEN_NPC_TV_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOC_NPC_TV_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L10_1","type":"dialog","speaker":"HELPER_NPC_TV_NULL","text":{"KOREA":"채플린 박사님? 그게 무슨 말씀이시죠? 무기는 슬라임 백작이 전부 먹어버린 게 아니었나요?","JPN":"チャップリン博士？　それはどういうことですか？　武器はスライム伯爵に全部食われたわけじゃないんですか？","ENG":"Dr. Chaplin? What do you mean? Didn't Count Slime eat all our weapons?","TWN":"卓別林博士？你這是什麼意思？武器不是已經被敵人全部奪走了嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAMEN_NPC_TV_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOC_NPC_TV_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOC_NPC_TV_NULL","text":{"KOREA":"가면 카운터! 지금부터 최종 비밀병기 Z를 보내줄 테니 잘 받아라!","JPN":"仮面カウンター！　今から最終秘密兵器Zを送るからしっかり受け取れ！","ENG":"Masked Counter! I'm sending you the Ultimate Secret Weapon Z now! Take it well!","TWN":"蒙面制裁者！現在我就將終極秘密武器Z送給你，接好了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAMEN_NPC_TV_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOC_NPC_TV_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L12_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"비밀병기 Z라면?","JPN":"秘密兵器Z？","ENG":"Secret Weapon Z, you say?","TWN":"秘密武器Z？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAMEN_NPC_TV_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOC_NPC_TV_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"과연…! 잘 알겠습니다.","JPN":"なるほど……！　わかりました。","ENG":"I see...! Understood.","TWN":"原來如此……！我明白了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAMEN_NPC_TV_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOC_NPC_TV_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"크하하! 비밀병기라고? 오히려 좋지! 그것도 내가 먹어버리면 그만이거든!","JPN":"クハハ！　秘密兵器だと？　いいだろう！　それも俺が食べてしまえば使えまい！","ENG":"Hahaha! A secret weapon? Even better! I'll eat it too and make it mine!","TWN":"哈哈哈！秘密武器？那反而更好！反正最終都會進我的肚子！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_03"},{"id":"L16_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"그렇게 쉽게 빼앗진 못할 거다! 슬라임 백작!","JPN":"そう簡単には奪わせないぞ！　スライム伯爵！","ENG":"You won't steal it so easily! Count Slime!","TWN":"可不會讓你那麼容易就得手！史萊姆伯爵！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"크윽?!","JPN":"くうっ！？","ENG":"Urgh?!","TWN":"呃？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HELPER_NPC_TV_NULL","text":{"KOREA":"꺄앗? 또 빼앗겼잖아!","JPN":"きゃあ？　また取られた！","ENG":"Kyaah? We lost another weapon!","TWN":"呃啊？！又被奪走了？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HELPER_NPC_TV_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"크하하! 큰소리 쳐놓고도 당하다니, 뭐하는 거냐! 가면 카운터!","JPN":"クハハ！　自信満々に言ったくせにやられるとは、いい気味だな！　仮面カウンター！","ENG":"Hahaha! You talk big, but end up taking a blow! What's going on? Masked Counter!","TWN":"哈哈哈！牛皮吹得那麼大，結果還是被打敗了，這算什麼啊，蒙面制裁者！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_04"},{"id":"L22_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"제 아무리 대단한 히어로라 해도 그 손에 무기가 없으면 무슨 수로 이기겠다는 거지?","JPN":"いくらすごいヒーローでも、手に武器もないのにどうやって勝つつもりなんだ？","ENG":"Even the greatest hero can't win without a weapon, right?","TWN":"就算是再厲害的英雄，手上沒有武器可怎麼贏呢？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"…아니.","JPN":"……いいや。","ENG":"...You're wrong.","TWN":"……不對！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KAMEN_NPC_TV_NULL","text":{"KOREA":"히어로는 가장 불리한 순간에 이긴다!","JPN":"ヒーローは一番不利な瞬間に勝つ！","ENG":"A hero wins even at the most disadvantageous moment!","TWN":"英雄之所以是英雄，就是因為他能在最劣勢的時候贏得勝利！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"아니? 그 대사는…?!","JPN":"そのセリフ……！？","ENG":"What? That line...?!","TWN":"那句台詞是……？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TV_CARTOON"},{"id":"L26_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"큭! 네 녀석! 궁지에 몰리고도 그런 배짱을 부리다니!","JPN":"くっ！　貴様！　ピンチに陥ってもまだ堂々としているなんて！","ENG":"You! Even cornered, you still have the guts to act like that?!","TWN":"這傢伙！都被逼到絕境了，居然還敢這麼囂張？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SLIME_NPC_TV_NULL","text":{"KOREA":"끝이다!!","JPN":"これで終わりだ！！","ENG":"It's over!!","TWN":"差不多就到這吧！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_20"},{"id":"L30_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"오오…!","JPN":"おお……！","ENG":"Ooh...!","TWN":"喔喔……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그거 재밌어?","JPN":"それ面白い？","ENG":"Is that fun?","TWN":"你覺得這很有趣？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"우앗?!","JPN":"うぁっ！？","ENG":"Whoa?!","TWN":"什麼？！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TV_CARTOON"},{"id":"L35_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장? 언제부터 뒤에서 보고 있었던 거야?","JPN":"隊長？　いつから後ろで見ていたんだ？","ENG":"Cap? How long have you been watching from behind?","TWN":"隊長？！你從什麼時候開始就在後面看著的？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"음- 클라이맥스 때부터 본 것 같은데.","JPN":"ん～クライマックスあたりからだと思うけど。","ENG":"Hmm, I think I've been watching since the climax.","TWN":"嗯……好像是從精彩部分開始看的。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"내용이 유치하지 않아? 별로 현실성도 없고.","JPN":"内容が子どもっぽくない？　リアリティーも少ないし。","ENG":"Isn't the plot a bit childish? It doesn't seem very realistic.","TWN":"內容會不會太幼稚了啊？一點也不現實。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"애들 보라고 만든 거 맞아. 저 곰탱이 수준엔 딱 맞았나 보지.","JPN":"子ども向けだからね。ブーちゃんには丁度いいレベルだったんでしょ。","ENG":"It's definitely made for children. Guess it's perfect for a nitwit like her.","TWN":"這是給小孩子看的吧，看起來和那隻大熊的智商剛好匹配。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭣? 내가 애라는 거냐?!","JPN":"は？　俺が子どもだっていうのか！？","ENG":"What? Are you calling me a kid?!","TWN":"什……？！你拿我當小孩？！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"괜찮지 않을까?","JPN":"いいんじゃないかな？","ENG":"It's probably okay, don't you think?","TWN":"這也沒什麼不好吧？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"우리, 어릴 땐 이런 거 볼 기회 같은 거 없었으니까. 지금이라도 실컷 즐기는 거지.","JPN":"私たちは子どもの頃にこういうものを見る機会がなかったから。今からでも存分に楽しまなくちゃ。","ENG":"We didn't have a chance to watch stuff like this when we were younger. Might as well enjoy it now.","TWN":"畢竟我們小時候根本沒機會看這些東西，現在就當是彌補缺憾了。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하긴, 그 말도 맞네.","JPN":"確かに、一理あるわね。","ENG":"Yeah, that's true.","TWN":"嗯，你說得對。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>학교</color>를 떠나기 전엔 누워서 만화나 볼 생각 같은 건 꿈에도 못 꿨으니까.","JPN":"<color=#ffd34c>学校</color>から抜け出す前は寝転んで漫画を読むなんて想像したこともなかったから。","ENG":"Before leaving <color=#ffd34c>school</color>, I never even dreamt I'd be lying down and watching cartoons.","TWN":"在脫離[學校]以前，我做夢也沒想到還能躺著看漫畫。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"말 잘 했어! 김소빈!","JPN":"よく言った！　コハル！","ENG":"Well said! Sobin!","TWN":"說得好！金素蘋！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이렇게 된 김에 가면 카운터 비밀병기 시리즈도 사주라! 한정판에다 완전 멋있다고!","JPN":"こうなったらさ、ついでに仮面カウンターの秘密兵器シリーズも買ってくれよ！　限定版でメチャクチャかっこいいんだ！","ENG":"Since we're at it, buy me the Masked Counter Secret Weapon series too! It's a limited edition and totally cool!","TWN":"既然如此，那就給我買蒙面制裁者秘密武器系列吧！這東西不僅是限量版，而且還超帥！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"엑? 장난감은 조금…","JPN":"えっ？　おもちゃはちょっと……","ENG":"Huh? Toys are a bit...","TWN":"欸？玩具就算了吧……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그런 쓸데없는 거에 돈 쓸 생각 마. 넌 가계부 쓰지도 않는 주제에.","JPN":"そんな無駄なことにお金を使わないで。家計簿も書かないくせに。","ENG":"Don't think about spending money on useless stuff like that. You don't even write in a ledger.","TWN":"你別想著在這種無聊的東西上浪費錢，連帳都不記的傢伙。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"치잇-","JPN":"ちぇー","ENG":"Tsk!","TWN":"哼！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 말이 맞아. 약값을 빼고 나면 식비도 간당간당하니까.","JPN":"その通りよ。薬代を差し引いたら食費も結構ぎりぎりなんだから。","ENG":"That's true. After paying for the medicine, the food budget is pretty tight.","TWN":"但你說得對，扣掉醫藥費，我們的伙食費才勉強夠用。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만… 우리도 진짜로 하나쯤 있으면 좋겠다. 가면 카운터의 비밀병기 같은 거.","JPN":"でも……私たちも1つくらいはあるといいわね。仮面カウンターの秘密兵器みたいなもの。","ENG":"Still... it would be great to have one. Something like Masked Counter's secret weapon.","TWN":"不過……如果我們真的能擁有一個蒙面制裁者秘密武器就好了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 지금처럼 쫓기지도 않고, 돈 많이 벌어서 약값 걱정도 사라질 텐데.","JPN":"そうしたら今みたいに追われることもなく、お金もたくさん稼いで薬代の心配もしなくて済むのに。","ENG":"Then we wouldn't be chased like this, and we could make a lot of money to cover the medicine.","TWN":"那樣的話，就不會像現在這樣被追著跑，還能賺很多錢，也就不用擔心醫藥費了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대장…","JPN":"隊長……","ENG":"Cap...","TWN":"隊長……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미안, 유진아. 내가 괜히 끼어들어서 중요한 장면을 놓쳐버렸네.","JPN":"ごめん、シロコ。私が口出したせいで重要なシーンを見逃しちゃったね。","ENG":"Sorry, Eujin. I interrupted and you missed an important scene.","TWN":"抱歉，劉珍。我不該打擾你，讓你錯過了重要場面。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"괜찮아. 이 편은 전에도 봤거든.","JPN":"いいよ。この回は前にも見たからさ。","ENG":"It's okay. I've seen this episode before.","TWN":"沒關係，我之前看過這一集。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저 장면은 특히 마음에 들어서, 자꾸 다시 보게 된단 말이지.","JPN":"特にあのシーンがお気に入りで、何回も見ちゃうんだよな。","ENG":"That scene really stuck with me, so I keep watching it again.","TWN":"只是因為特別喜歡那一幕，所以才會反復看。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래? 다행이다.","JPN":"そう？　よかった。","ENG":"Really? I'm glad.","TWN":"是嗎？那就好。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 그 슬라임 백작을 무찌른 비밀병기라는 건… 결국 뭐였어?","JPN":"それじゃスライム伯爵を倒す秘密兵器っていうのは……結局何だったの？","ENG":"So, what was the secret weapon... that defeated Count Slime?","TWN":"那麼，打敗史萊姆伯爵的秘密武器到底是什麼？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"베에-","JPN":"ベえー","ENG":"Blegh!","TWN":"呸——"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_39"},{"id":"L19_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그건 비라는 거야. 갓 태어난 너한테 비는 처음 보는 광경이겠네.","JPN":"それは雨というものよ。生まれたばかりのあなたには初めて見る光景なのかもね。","ENG":"That's rain. It's probably the first time you've seen it, since you were just born.","TWN":"是雨喔。對於剛出生的你來說，雨還是第一次見到的景象吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_59"},{"id":"L21_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"비… 뭔지 알아.","JPN":"雨……何か知っている。","ENG":"Rain... I know what it is.","TWN":"雨……我知道。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_DESPAIR"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_40"},{"id":"L22_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"하지만 맛에 대한 정보는 없으니까.","JPN":"でも味に関する情報はないから。","ENG":"But I don't have any information about the taste.","TWN":"只是沒有任何關於味道的資訊。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_41"},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"배운 적도 없는 사람 말을 할 때부터 짐작은 했어.","JPN":"習ったこともないはずの人間の言葉を話した時から考えてはいたの。","ENG":"I've thought it the moment you started talking without ever learning how to speak.","TWN":"從你開始口吐人言時起，我就注意到了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_60"},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"다른 사람의 힘을 빼앗으면, 그 사람이 가진 정보도 같이 얻는 거지?","JPN":"他人の力を奪うと、その人が持っている情報も一緒に手に入るんでしょ？","ENG":"If you take someone else's power, you also get their information, right?","TWN":"你奪取他人的力量時，也能同時獲得那個人所擁有的資訊，對嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_61"},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"아무렴 비를 마셔본 사람은 없을 테니까.","JPN":"確かに、雨を飲んでみた人はいないだろうから。","ENG":"Of course, no one tries to taste rain.","TWN":"可惜目前為止還沒人喝過雨水。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_62"},{"id":"L26_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…맛없어.","JPN":"……不味い。","ENG":"...Not tasty.","TWN":"……不好喝。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_DESPAIR"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_42"},{"id":"L27_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"카운터의 힘. 역시 그게 제일 좋아.","JPN":"カウンターの力。やはりこれが一番いい。","ENG":"The power of a Counter. That's definitely the best.","TWN":"果然還是制裁者的力量最好吃！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_43"},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"너, 가면 카운터라고 들어봤어?","JPN":"あなた、仮面カウンターって聞いたことある？","ENG":"Have you heard of the Masked Counter?","TWN":"你，聽說過蒙面制裁者嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_63"},{"id":"L29_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_DESPAIR"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"어린애들이나 좋아하는… 유치한 만화 영화.","JPN":"子どもたちが好きな……子どもっぽいアニメーション。","ENG":"A childish cartoon movie... that only kids like.","TWN":"只有小孩子才喜歡的……幼稚的動畫。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_44"},{"id":"L31_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그래, 맞아.","JPN":"そう、そのとおりよ。","ENG":"Yes, you're correct.","TWN":"是啊，你說得對。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_64"},{"id":"L32_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"하지만 어린애들이 보는 만화라고 해서, 어른에게 배울 점이 없는 건 아니더라고.","JPN":"でも子どもが見るアニメだからって、大人が学べるものがないわけではなかったのよね。","ENG":"But just because it's a cartoon for kids doesn't mean there's nothing adults can learn from it.","TWN":"但就算是小孩子看的漫畫，大人也能從中學到一些東西。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_65"},{"id":"L34_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"행동으로 선악을 나누는 잣대와… 긍정과 응원은 힘을 준다는 얄팍한 교훈 같은 거 말인가?","JPN":"行動で善悪を区分することや……肯定と応援は力になるという浅はかな教訓のことを言うの？","ENG":"You mean its shallow lesson that separates good and evil by actions... and saying how affirmation and cheers give power?","TWN":"你是說用行動去定義善惡……或者說，得到正能量與鼓勵就能帶來力量，這種淺顯的道理？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_45"},{"id":"L35_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"그런 건 어른에게 아무런 쓸모도 없어. 나한테도 마찬가지고.","JPN":"そんなもの大人には無駄よ。私にもね。","ENG":"Such things are useless for adults, and the same goes for me.","TWN":"這些東西對大人來說毫無用處，對我來說也是一樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_46"},{"id":"L37_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"아하하, 난 그런 어려운 말로 널 가르치려는 게 아냐.","JPN":"あはは、私はそんな難しい言葉であなたに説教したいんじゃないわ。","ENG":"Ah hah hah, I'm not here to teach you using complicated words.","TWN":"哈哈哈，我可不是想給你講大道理。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_66"},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"세상의 모든 무기를 먹어 치우는 슬라임 백작이란 악당이 있었는데, 그 녀석이 어떻게 당했는지 알아?","JPN":"世の中の全ての武器を食らいつくすスライム伯爵っていう悪党がいたんだけど、そいつがどうやって倒されたか知ってる？","ENG":"There was a villain called Count Slime who devoured every weapon in the world. Do you know how he got defeated?","TWN":"世上有個能吞噬所有武器的史萊姆伯爵這個反派，你知道它是怎麼被打敗的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_67"},{"id":"L39_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그 먹보가 폭탄까지 먹어 치웠거든. 그래서 펑- 하고 터져버린 거야.","JPN":"その食いしん坊は爆弾まで全部食べて。それでド～ンって爆発しちゃったのよ。","ENG":"That glutton even ate a bomb. And BOOM...! He exploded.","TWN":"它吃掉了炸彈。然後——砰！連自己都給炸死了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_68"},{"id":"L40_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"역시 인간과의 대화는 무익해. 너처럼 교활한 인간이 상대라면 더더욱 그렇고.","JPN":"やはり人間との対話は無意味ね。あなたみたいなずる賢い人間が相手ならなおさら。","ENG":"Talking to humans is pointless, especially when the person I'm dealing with is as sly as you.","TWN":"果然，與人類多說無益。尤其是像你這樣狡猾的人類。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_47"},{"id":"L44_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"솔로베를 먹고 나면, 넌 나한테 쓸모 없어.","JPN":"ソロベーを食べたら、あなたもういらない。","ENG":"Once I've eaten Solovey, you'll be of no use to me.","TWN":"等我吃掉蘇羅薇後，你就沒有任何利用價值了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_48"},{"id":"L45_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"그러니까 죽일래.","JPN":"だから殺す。","ENG":"That's why I'll kill you.","TWN":"所以，我還是要殺掉你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_49"},{"id":"L46_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"힘 없고 맛도 없는 인간을 해치겠다니. 네 기분을 상하게 한 벌 같은 걸까나?","JPN":"力もなく美味しくもない人間を殺すって。あなたの機嫌を損ねた罰なのかな？","ENG":"Hurting a powerless and tasteless human. Could it be a punishment for upsetting you?","TWN":"要殺掉毫無力量又不好吃的人類嗎？是因為生我氣讓你心情不好，要懲罰我嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_69"},{"id":"L47_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"넌 거짓말이 많아. 분명 말로 날 속이거나 혼란을 줄 거야.","JPN":"あなた、ウソが多いわ。きっとウソで私を騙したり混乱させたりする。","ENG":"You lie a lot. You'll surely try to deceive or confuse me with your words.","TWN":"你撒了很多謊，肯定會用言語欺騙我，讓我困惑。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_DESPAIR"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_50"},{"id":"L48_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"그리고 집착과 복수심. 살아있으면 날 쫓아다니며 방해하려 하겠지. 살려둘 이유가 없어.","JPN":"そして執着と復讐心。生きていれば私を追いかけて邪魔しようとするはず。生かしておく理由がない。","ENG":"And obsession and revenge. If I keep you alive, you'll just follow me around and try to interfere. So there's no reason to spare you.","TWN":"而且你還會執著於復仇。如果你活著，肯定會不斷追殺我，妨礙我。既然如此，就沒理由留著你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_51"},{"id":"L49_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"후후, 날 맛본 것만으로 전부 꿰뚫어보다니. 너무 정확해서 기분 나쁜데?","JPN":"ふふ、私を味見しただけで全部見抜くなんて。あまりにも正確で気持ち悪いわね？","ENG":"Haha, you've figured me out just from tasting me. It's so accurate that it's creepy, you know?","TWN":"呵呵，光是吃了我一口，就能把我看穿嗎？太準確了，真是令人不爽呢？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_70"},{"id":"L50_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…왔구나.","JPN":"……来たわね。","ENG":"...You're here.","TWN":"……你來了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_52"},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"언니를 데려갈 거에요.","JPN":"姉さんを連れて行きます。","ENG":"I'm going to take Sis back.","TWN":"我要帶走姊姊。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_51"},{"id":"L11_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"인간에겐 자신보다 소중한 건 드물어.","JPN":"人間にとって自分より大事なものは珍しい。","ENG":"Humans rarely have anything more valuable than themselves.","TWN":"對人類來說，比自己更重要的東西可並不多。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_53"},{"id":"L12_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"진다는 걸 알면서도 혼자 올 정도로, 그 인간이 너에게 그렇게나 중요한 거야?","JPN":"負けるとわかっているくせに1人で来るほど、この人間があなたにとって大事な存在なの？","ENG":"Even knowing you'll lose, you came alone. Does that mean this human is that important to you?","TWN":"明知道會輸卻還是獨自前來，那個人對你來說就那麼重要嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_54"},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"중요해요.","JPN":"大事です。","ENG":"Yes, she is very important.","TWN":"重要。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_52"},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그리고 난 당신한테 질 생각이 없고요.","JPN":"そして私は負ける気もありません。","ENG":"And I have no intention of losing to you.","TWN":"而且我也沒打算輸給你。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_53"},{"id":"L15_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"너의 사고방식은 다른 인간들과 다르네.","JPN":"あなたの考え方は他の人間とは違うわね。","ENG":"Your way of thinking is different from other humans.","TWN":"你的思考方式和其他人類不同呢。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_55"},{"id":"L16_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"나에게 지는 경험을 하고도 이길 거라 생각하다니.","JPN":"私に負けたことがあるくせに勝つと思っているなんて。","ENG":"To think you can win after already losing to me once.","TWN":"即便經歷了失敗，你還是覺得能贏過我嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CORRUPTED_C_MIMIC_IN_TRAILER_56"},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"몇 번이든 상관없어.","JPN":"何回でもいい。","ENG":"It doesn't matter how many times it takes.","TWN":"無論多少次都無所謂。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_54"},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"내가 좋아하는 사람을… 더는 침식 따위에 잃지 않을 거니까.","JPN":"好きな人を……これ以上侵食なんかで失ったりはしないから。","ENG":"I won't lose the person I care about... to something like Corruption.","TWN":"我再也不會讓喜歡的人……因侵蝕而被奪走！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_55"}]`);export{e as default};